#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define WIDTH 800
#define HEIGHT 600

typedef struct { float x, y, z; } Vec3;
typedef struct { Vec3 o, d; } Ray;
typedef struct { Vec3 c; float r; } Sphere;
typedef struct { Vec3 p; float t; Vec3 n; int hit; } Hit;

static Sphere SPH = {{0.0f, -0.5f, -5.0f}, 1.0f};

static Vec3 normalize3(float x, float y, float z){
    float l = sqrtf(x*x + y*y + z*z);
    Vec3 v = { x/l, y/l, z/l };
    return v;
}

static Hit sphere_intersect(Sphere s, Ray r){
    Hit h;
    float ocx = r.o.x - s.c.x, ocy = r.o.y - s.c.y, ocz = r.o.z - s.c.z;
    float a = r.d.x*r.d.x + r.d.y*r.d.y + r.d.z*r.d.z;
    float b = 2.0f*(ocx*r.d.x + ocy*r.d.y + ocz*r.d.z);
    float c = ocx*ocx + ocy*ocy + ocz*ocz - s.r*s.r;
    float disc = b*b - 4.0f*a*c;
    if (0.0f > disc){ h.hit = 0; return h; }
    double sq = sqrt((double)disc);
    double den = (double)(2.0f*a);
    float tf = (float)(((double)(-b) - sq)/den);
    if (!(0.001f <= tf)){
        tf = (float)(((double)(-b) + sq)/den);
        if (!(0.001f <= tf)){ h.hit = 0; return h; }
    }
    h.p.x = r.o.x + r.d.x*tf;
    h.p.y = r.o.y + r.d.y*tf;
    h.p.z = r.o.z + r.d.z*tf;
    h.n = normalize3(h.p.x - s.c.x, h.p.y - s.c.y, h.p.z - s.c.z);
    h.t = tf; h.hit = 1;
    return h;
}

static Vec3 sky_color(Vec3 d){
    float t = 0.5f*(d.y + 1.0f);
    float omt = 1.0f - t;
    Vec3 col = { t*0.5f + omt, t*0.7f + omt, omt + t };
    return col;
}

static Vec3 trace(Ray r, Vec3 light){
    Hit hs = sphere_intersect(SPH, r);
    int material = 0; float bt = 0.0f; Vec3 P = {0,0,0}, N = {0,0,0}; int have = 0;
    if (hs.hit){ have = 1; material = 1; bt = hs.t; P = hs.p; N = hs.n; }
    if (fabsf(r.d.y) >= 0.0001f){
        float t = (-1.5f - r.o.y)/r.d.y;
        if (t >= 0.001f){
            if (!have || t <= bt){
                have = 1; material = 0; bt = t;
                P.x = r.o.x + r.d.x*t;
                P.y = r.o.y + r.d.y*t;
                P.z = r.o.z + r.d.z*t;
                N.x = 0.0f; N.y = 1.0f; N.z = 0.0f;
            }
        }
    }
    if (!have) return sky_color(r.d);
    Ray sr;
    sr.o.x = P.x + N.x*0.001f;
    sr.o.y = P.y + N.y*0.001f;
    sr.o.z = P.z + N.z*0.001f;
    sr.d = normalize3(light.x, light.y, light.z);
    Hit sh = sphere_intersect(SPH, sr);
    float intensity;
    if (sh.hit){
        intensity = 0.2f;
    } else {
        float dot = N.x*light.x + N.y*light.y + N.z*light.z;
        double dd = fmax((double)dot, 0.0);
        intensity = (float)dd * 0.8f + 0.2f;
    }
    Vec3 col;
    if (material){
        col.x = intensity; col.y = 0.2f*intensity; col.z = 0.2f*intensity;
    } else {
        int idx = (int)((double)floorf(P.x) + (double)floorf(P.z));
        float ch = (idx & 1) ? 0.4f : 0.9f;
        col.x = ch*intensity; col.y = ch*intensity; col.z = ch*intensity;
    }
    return col;
}

static void write_image(const char *fn, Vec3 **img, int w, int h){
    FILE *f = fopen(fn, "w");
    if (!f){ fprintf(stderr, "Error: Could not open file %s for writing\n", fn); return; }
    fprintf(f, "P3\n%d %d\n255\n", w, h);
    for (int y = 0; y < h; y++){
        for (int x = 0; x < w; x++){
            Vec3 p = img[y][x];
            double r = fmin(fmax((double)p.x, 0.0), 1.0);
            double g = fmin(fmax((double)p.y, 0.0), 1.0);
            double b = fmin(fmax((double)p.z, 0.0), 1.0);
            fprintf(f, "%d %d %d\n", (int)((float)r*255.99f), (int)((float)g*255.99f), (int)((float)b*255.99f));
        }
    }
    fclose(f);
    fprintf(stderr, "Wrote image to %s\n", fn);
}

int main(void){
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", WIDTH, HEIGHT);
    fputs("This will be downsampled with ffmpeg after rendering\n", stderr);
    Vec3 light = normalize3(1.0f, 1.0f, -1.0f);
    Vec3 **img = malloc(HEIGHT*sizeof(Vec3*));
    for (int y = 0; y < HEIGHT; y++) img[y] = malloc(WIDTH*sizeof(Vec3));
    fputs("Rendering high-resolution image...\n", stderr);
    float aspect = (float)WIDTH/(float)HEIGHT;
    for (int y = 0; y < HEIGHT; y++){
        float pct = 100.0f*(float)y/600.0f;
        fprintf(stderr, "\rProgress: %.1f%%", (double)pct);
        float v = (float)y/599.0f;
        for (int x = 0; x < WIDTH; x++){
            float u = (float)x/799.0f;
            Vec3 d;
            d.x = u*(2.0f*aspect) - aspect;
            d.y = 2.0f*(1.0f - v) - 1.0f;
            d.z = -1.0f;
            Ray r; r.o.x = 0.0f; r.o.y = 0.0f; r.o.z = 0.0f;
            r.d = normalize3(d.x, d.y, d.z);
            img[y][x] = trace(r, light);
        }
    }
    fputs("\nRendering complete\n", stderr);
    write_image("image.ppm", img, WIDTH, HEIGHT);
    for (int y = 0; y < HEIGHT; y++) free(img[y]);
    free(img);
    fputs("Done.\n", stderr);
    return 0;
}

